#define NP namespace
using NP std;
namespace FAST_IO{
	const int LEN=1<<17;
	char BUF[LEN],PUF[LEN];
	int Pin=LEN,Pout;
	inline void flushin(){memcpy(BUF,BUF+Pin,LEN-Pin),fread(BUF+LEN-Pin,1,Pin,stdin),Pin=0;return;}
	inline void flushout(){fwrite(PUF,1,Pout,stdout),Pout=0;return;}
	inline char Get(){return BUF[Pin++];}
	inline void Put(char x){PUF[Pout++]=x;}
	template<typename tp=int>inline tp read(){(Pin+32>=LEN)?flushin():void();tp res=0;char ch=' ';for(;ch<'0'||ch>'9';ch=Get());for(;ch>='0'&&ch<='9';ch=Get())res=(res<<3)+(res<<1)+ch-48;return res;}
	template<typename tp>inline void write(tp a,char b='\n')
	{
		static int stk[20],top;
		(Pout+32>=LEN)?flushout():void();
		if(!a)Put('0');
		for(!top;a;a/=10)stk[++top]=a%10;
		for(;top;--top)Put(stk[top]^48);
		Put(b);
		return;
	}
}
using NP FAST_IO;
int n,ans=0,now=0,a[100005];
bitset<100005>f;
signed main(void)
{
    n=read();
	FOR(i,1,n)
    {
		int x=read();
		if(f[x])
        {
			wh(a[now]<x)ans=max(ans,a[now]),--now;
			if(a[now]!=x)ans=max(ans,x);
		}
		a[++now]=x;
		f[x]=1;
	}
	write(ans);
    flushout();
}
